solution_code:
#include <iostream>
#include <stdexcept>
#include <string>

struct Guard {
    std::string name;
    Guard(const std::string& n) : name(n) {
        std::cout << name << " constructed\n";
    }
    ~Guard() {
        std::cout << name << " destroyed\n";
    }
};

void c() {
    Guard g("C");
    throw std::runtime_error("error");
}

void b() {
    Guard g("B");
    c();
}

void a() {
    Guard g("A");
    b();
}

int main() {
    try {
        a();
    } catch (const std::runtime_error& e) {
        std::cout << "Caught: " << e.what() << "\n";
    }
    return 0;
}

