solution_code:
#include <iostream>
#include <stdexcept>

void inner() {
    throw std::runtime_error("value too large");
}

void middle() {
    try {
        inner();
    } catch (const std::runtime_error& e) {
        throw; // re-throw so main can catch it
    }
}

int main() {
    try {
        middle();
    } catch (const std::runtime_error& e) {
        std::cout << "Caught in main: " << e.what() << "\n";
    }
    return 0;
}
